function vertexAt(mx, my, ws, scale) {
  const polys = ws.polygonsByCamera[ws.activeCameraId];
  for (let i = polys.length - 1; i >= 0; i--) {
    const hit = polys[i].points.findIndex(p => Math.hypot(p.x * imgW - mx, p.y * imgH - my) <= HIT.VERTEX_PX / scale);
    if (hit !== -1) return { polyId: polys[i].id, index: hit };
  }
